INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('real-estate-moex-01662', 'real-estate', 'real-estate-moex-103-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '風靜了，我是／默默的雪。他在／敗葦間穿行，好落寞的人／神色，遣人一朝是／ 東京八十萬禁軍教頭／如今行船，悄悄／向梁山落草／山是憂愁的樣子（楊牧） 此詩所寫人物應為：', '["屈原", "項羽", "林沖", "岳飛"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01663', 'real-estate', 'real-estate-moex-103-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '「碩鼠碩鼠，無食我黍！三歲貫女，莫我肯顧。逝將去女，適彼樂土。樂土樂土， 爰得我所。」（《詩經‧魏風‧碩鼠》）詩中之「碩鼠」是用以說明：', '["執政者的貪污腐敗", "百姓不知勤於農耕", "天災對農作的傷害", "鼠患對農村的摧殘"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01664', 'real-estate', 'real-estate-moex-103-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '如果有一個文化活動，四周以菊花和柳樹布置，並張貼著「口吟歸去來，頭戴漉酒 巾」的對聯，可以推測這個活動和那個古人有關？', '["屈原", "陶潛", "杜甫", "周敦頤"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01665', 'real-estate', 'real-estate-moex-103-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '曹操〈短歌行〉：「月明星稀，烏鵲南飛。繞樹三匝，何枝可依？山不厭高，水不 厭深。周公吐哺，天下歸心。」引文中「山不厭高，水不厭深」，意指：', '["品德崇高", "廣納賢才", "景色壯麗", "胸羅萬象 60210"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01666', 'real-estate', 'real-estate-moex-103-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '《論語‧先進》：「夫子喟然歎曰：吾『與』點也。」文句中「與」字的意義和用 法，和下列選項中那一個相同？', '["選賢「與」能，講信修睦", "日月逝矣，歲不我「與」", "或乞醯焉，乞諸其鄰而「與」之", "暴虎馮河，死而無悔者，吾不「與」也"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01667', 'real-estate', 'real-estate-moex-103-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '下列楹聯何者使用正確？', '["書房：琴瑟永諧千歲樂，芝蘭同介百年春", "廳堂：舉目思祖功宗德，存心為孝子賢孫", "宗祠：門前莫約頻來客，座上同觀未見書", "園亭：水色山光皆畫本，花香鳥語是詩情"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01668', 'real-estate', 'real-estate-moex-103-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '「人類所造作的世間的種種現象，迷塞了我的心眼，隱蔽了我的本性，使我對於擾 攘奔逐的地球上的生活，漸漸習慣，視為人生的當然而恬不為怪。實則墮地時的 我的本性，已經斵喪無餘了。」（豐子愷〈阿難〉）本段話認為人隨著年齡與閱 歷，會漸漸習慣的是：', '["人情練達", "剛愎成性", "絕聖棄智", "矯飾偽行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01669', 'real-estate', 'real-estate-moex-103-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '黃崑巖：「有教養的人是有智慧的人，要達到這境界，光是有知識還不能稱得上有 教養。教養的重要要素是對自己存在的意義充分了解，而這種自覺出自於自身對周 遭環境的相對位置的正確概念。自身與環境，包括自身與別人或與社會的關係要弄 清楚。知道了這種關係脈絡，我們的進退才有分寸又能見好就收。」（《給青年學 生的十封信》）下列選項何者合乎文中所說教養的特質？', '["寬以待人，嚴以律己", "忠人之事，克盡己職", "知己知彼，行己有方", "捨己為公，有容乃大"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01670', 'real-estate', 'real-estate-moex-103-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '我們的社會結構原則，建立在一系列不等同的價值取向上面。這個價值系列的頂端 是天下、國家，底部躺著個人。這個「個人」，格物致知的修身工夫，意義不在探 討「本人」存在的意義，也不是為了追求對外在世界的認知，而是為了把自己準備 完善，以實現家族、國家和天下的和諧穩定。（劉大任〈賭〉）下列選項何者最接 近上文所述之文化？', '["個人主義", "群體主義", "存在主義", "人本主義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01671', 'real-estate', 'real-estate-moex-103-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '皮克斯動畫導演柏德曾說：「員工士氣往往對電影預算帶來最大衝擊，但卻從來不 會顯現在預算表上。如果員工士氣低落，那麼你花的每一塊錢，實際上只會得到兩 毛五的價值。如果員工士氣高，那麼你花的每一塊錢，可能創造出三塊錢的價值。 每家公司都應該更重視員工士氣。」關於這段話表達的主旨，最適當的詮釋是：', '["員工士氣是電影成敗的關鍵", "員工士氣高可提高經費運用的產值", "員工士氣的高低落差可達到十二倍", "預算表並不能精確估算完整的收支情形 60210"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "05e7f465f23c", "answer_pdf_sha1": "4cb4614a7d21", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
